architecture BEHAVIORAL of CNTR_4BIN_ASCLR_NI is
signal Q: STD_LOGIC_VECTOR(3 downto 0);

begin
 RCO<=Q(3) and Q(2) and Q(1) and Q(0) and ENT;
 process(CLR,CLK,LOAD,ENP,ENT,D,C,B,A)
