 if CLR='0' then  Q<="0000";
 elsif rising_edge(CLK) then 
  if LOAD='0' then Q<=D&C&B&A;
  elsif (ENP and ENT)='1' then Q<=Q+"0001";
  end if;
 end if;
 end process;
 QD<=Q(3);
 QC<=Q(2);
 QB<=Q(1);
 QA<=Q(0);	
end BEHAVIORAL;

