library work;
use work.Stage3_stable_edition_pkg.ALL;
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity SR_4BIDI_NI is
 port (
   A : in STD_LOGIC;
   B : in STD_LOGIC;
   C : in STD_LOGIC;
   D : in STD_LOGIC;
   S0 : in STD_LOGIC;
   S1 : in STD_LOGIC;
   CLR : in STD_LOGIC;
   CLK : in STD_LOGIC;
   SR : in STD_LOGIC;
   SL : in STD_LOGIC;
   QA : out STD_LOGIC;
   QB : out STD_LOGIC;
   QC : out STD_LOGIC;
   QD : out STD_LOGIC 
  );
end SR_4BIDI_NI;

architecture BEHAVIORAL of SR_4BIDI_NI is  
signal OUTP: STD_LOGIC_VECTOR(0 to 3);
 
begin
 process(CLR, CLK, SR, SL, S0, S1, A, B, C, D)
 begin
 if CLR = '0' then
 	    OUTP<="0000";
      elsif (CLK='1' and CLK'event) then
	  if (S1='1' and S0='1') then OUTP<=A&B&C&D;
	     elsif ( S1='0' and S0='1') then  OUTP<=SR& OUTP(0 to 2);
                     elsif  ( S1='1' and S0='0') then OUTP<=OUTP(1 to 3)&SL;
	  end if;	
 end if;
 end process;	
 QD<=OUTP(3);
 QC<=OUTP(2);
 QB<=OUTP(1);
 QA<=OUTP(0);
  end BEHAVIORAL;

